"""asym cap b0.05 s0.057."""
def get_trading_params(ms):
    dt = ms.get("decision_type", "deploy")
    if dt == "deploy":
        pt = ms.get("prob_table", {})
        bp = sum(pt.get(("buy",t,h),0.5) for t in [10,20,30] for h in [24,48]) / 6
        sp = sum(pt.get(("sell",t,h),0.5) for t in [10,20,30] for h in [24,48]) / 6
        d = bp - sp
        if d > 0.05:
            dr = "both"
            rd = 125
        elif d < -0.057:
            dr = "both"
            rd = 125
        elif d > 0.0119:
            dr = "buy"
            rd = 107
        elif d < -0.01175:
            dr = "sell"
            rd = 107
        else:
            dr = "both"
            rd = 107
        if ms.get("days_since_last_blowup",999) < 7:
            return {"action":"skip_deploy","skip_bars":1440}
        return {"grid_pips":3,"tp_pips":80,"base_lots":0.01,"max_depth":22,"recovery_d_pips":rd,"stake_per_account":1000,"target_balance":0,"basket_direction":dr}
    if dt == "recovery":
        return {"action":"fire_recovery","recovery_tp_pips":30,"recovery_risk_pct":0.80,"recovery_max_adverse_pips":57}
    return {}
